                problemStatusResent: false,
                platform: '',
                platformFallback: '',
                autoNextEnabled: false,
                isShowPageValue: (typeof isShowPage !== 'undefined'),
                isUtahDomainValue: (typeof isUtah === 'undefined' || !isUtah),
